// Build the owner WhatsApp alert — sent once per batch with intelligence summary
const d = $input.first().json;

if (!d.toProcess || d.toProcess.length === 0) {
  return [{ json: { skipAlert: true } }];
}

// Find the highest-value at-risk cart
const sortedByValue = [...d.toProcess].sort((a, b) => b.cart.cartValue - a.cart.cartValue);
const topCart = sortedByValue[0];

// Approach distribution
const counts = d.counts || {};
const channelCounts = { email: 0, whatsapp: 0, both: 0 };
d.toProcess.forEach(p => {
  if (p.sendEmail && p.sendWhatsapp) channelCounts.both++;
  else if (p.sendEmail) channelCounts.email++;
  else if (p.sendWhatsapp) channelCounts.whatsapp++;
});

// Touch breakdown
const touchBreakdown = { t1: 0, t2: 0, t3plus: 0 };
d.toProcess.forEach(p => {
  const t = p.decision.touch_number || 1;
  if (t === 1) touchBreakdown.t1++;
  else if (t === 2) touchBreakdown.t2++;
  else touchBreakdown.t3plus++;
});

// Build the alert message
const lines = [];
lines.push('🛒 *Cart Recovery Batch — ' + new Date().toLocaleTimeString('en-IN', {hour:'2-digit', minute:'2-digit'}) + '*');
lines.push('');
lines.push('📊 *' + d.processCount + ' carts engaged*');
lines.push('💰 ₹' + d.totalValueAtStake.toLocaleString('en-IN') + ' total at stake');
lines.push('🎁 ₹' + d.totalPotentialSavings.toLocaleString('en-IN') + ' total discounts offered');
lines.push('');
lines.push('*🎯 Approach Mix:*');
if (counts.NUDGE_NO_DISCOUNT) lines.push('• ' + counts.NUDGE_NO_DISCOUNT + ' x No-discount nudge');
if (counts.SOFT_DISCOUNT_10) lines.push('• ' + counts.SOFT_DISCOUNT_10 + ' x Soft 10% off');
if (counts.URGENT_DISCOUNT_15) lines.push('• ' + counts.URGENT_DISCOUNT_15 + ' x Urgent 15% off');
if (counts.LOYALTY_DISCOUNT_20) lines.push('• ' + counts.LOYALTY_DISCOUNT_20 + ' x Loyalty 20% off');
if (counts.WIN_BACK_25) lines.push('• ' + counts.WIN_BACK_25 + ' x Win-back 25% off');
lines.push('');
lines.push('*📲 Touch Mix:*');
lines.push('• T1: ' + touchBreakdown.t1 + ' first reminder');
lines.push('• T2: ' + touchBreakdown.t2 + ' follow-up');
lines.push('• T3+: ' + touchBreakdown.t3plus + ' last chance');
lines.push('');
lines.push('*🚨 Highest Value At Risk:*');
lines.push(topCart.cart.customerName + ' (' + topCart.cart.profile.customerTier + ')');
lines.push('₹' + topCart.cart.cartValue.toLocaleString('en-IN') + ' • ' + topCart.decision.approach.replace(/_/g,' '));
lines.push('');
if (d.batchSummary) {
  lines.push('*💡 AI Strategy:*');
  lines.push(d.batchSummary);
}

return [{ json: { ownerAlert: lines.join('\n'), skipAlert: false } }];

// Filter to PENDING carts only + enrich each with customer history + learning data
// PLUS: skip any cart that has been messaged in the last 24 hours (Recovery_Log cooldown)
const cartRows = $('📊 Read Abandoned Carts').all().map(i => i.json);
const customers = $('👥 Read Customer History').all().map(i => i.json);
const recoveries = $('📈 Read Recovery Log (Learning)').all().map(i => i.json);

const num = (v) => { const n = parseFloat(String(v).replace(/[^0-9.\-]/g,'')); return isNaN(n)?0:n; };
const nowMs = Date.now();

// Build cooldown set: cart IDs messaged in the last 24 hours
const COOLDOWN_HOURS = 24;
const recentlyMessaged = {};
recoveries.forEach(r => {
  const cartId = r['Cart ID'];
  if (!cartId) return;
  const sentAt = r['Sent At'] ? new Date(r['Sent At']).getTime() : 0;
  if (!sentAt || isNaN(sentAt)) return;
  const hoursAgo = (nowMs - sentAt) / 3600000;
  if (hoursAgo < COOLDOWN_HOURS) {
    recentlyMessaged[cartId] = true;
  }
});

// Index customers
const custByEmail = {};
const custByPhone = {};
customers.forEach(c => {
  if (c['Email']) custByEmail[String(c['Email']).toLowerCase().trim()] = c;
  if (c['Phone']) custByPhone[String(c['Phone']).replace(/[^0-9]/g,'').slice(-10)] = c;
});

// Compute success rates per approach (learning data for the AI)
const approachStats = {};
recoveries.forEach(r => {
  const ap = r['Approach Used'] || 'unknown';
  if (!approachStats[ap]) approachStats[ap] = { sent: 0, recovered: 0, revenue: 0 };
  approachStats[ap].sent++;
  if (String(r['Outcome']).toUpperCase() === 'RECOVERED') {
    approachStats[ap].recovered++;
    approachStats[ap].revenue += num(r['Recovered Value']);
  }
});
Object.keys(approachStats).forEach(k => {
  const s = approachStats[k];
  s.successRate = s.sent > 0 ? +(s.recovered / s.sent * 100).toFixed(1) : 0;
  s.avgRevenue = s.recovered > 0 ? Math.round(s.revenue / s.recovered) : 0;
});

// Filter pending carts
const pending = [];
cartRows.forEach(c => {
  const cartId = c['Cart ID'];
  if (!cartId) return; // sanity: skip rows without cart ID

  // SKIP if already messaged in the last 24 hours
  if (recentlyMessaged[cartId]) return;

  // SKIP if status is anything except blank or PENDING
  const status = String(c['Status'] || '').toUpperCase().trim();
  if (status && status !== 'PENDING') return;

  const abandonedAt = c['Abandoned At'] ? new Date(c['Abandoned At']) : null;
  if (!abandonedAt || isNaN(abandonedAt)) return;
  const minsSince = (nowMs - abandonedAt.getTime()) / 60000;

  // Window: 15 minutes (just abandoned) to 48 hours (fresh enough to recover)
  if (minsSince < 15 || minsSince > 2880) return;

  // Lookup customer
  const email = String(c['Customer Email'] || '').toLowerCase().trim();
  const phone = String(c['Customer Phone'] || '').replace(/[^0-9]/g,'').slice(-10);
  const customer = custByEmail[email] || custByPhone[phone] || null;
  if (!email && !phone) return; // need at least one contact channel

  const profile = customer ? {
    isReturning: true,
    lifetimeOrders: num(customer['Lifetime Orders']),
    lifetimeValue: num(customer['Lifetime Value']),
    avgOrderValue: num(customer['Avg Order Value']),
    lastOrderDays: num(customer['Days Since Last Order']),
    abandonHistory: num(customer['Past Abandons']),
    pastRecoveries: num(customer['Past Recoveries']),
    favoriteCategory: customer['Favorite Category'] || '',
    lastDiscountUsed: num(customer['Last Discount Used']),
    customerTier: customer['Tier'] || 'standard',
    prefersChannel: customer['Preferred Channel'] || 'email'
  } : { isReturning: false, lifetimeOrders: 0, lifetimeValue: 0, avgOrderValue: 0, lastOrderDays: 0, abandonHistory: 0, pastRecoveries: 0, customerTier: 'new', prefersChannel: 'email' };

  pending.push({
    cartId,
    customerEmail: email,
    customerPhone: phone,
    customerName: c['Customer Name'] || 'there',
    products: c['Products'] || '',
    cartValue: num(c['Cart Value']),
    currency: c['Currency'] || 'INR',
    lastViewedProduct: c['Last Viewed Product'] || '',
    timeOnSite: num(c['Time on Site Mins']),
    source: c['Source'] || 'Web',
    abandonedAt: c['Abandoned At'],
    minsSinceAbandon: Math.round(minsSince),
    profile
  });
});

return [{ json: { pendingCarts: pending, approachStats, pendingCount: pending.length, recentlyMessagedCount: Object.keys(recentlyMessaged).length, runTime: new Date().toISOString() } }];

// Parse decisions with STRICT validation, generate promo codes, compute savings
const aiResp = $input.first().json;
const d = $('🔧 Build Strategist Prompt').first().json;

let analysis = { decisions: [], batch_summary: 'Parse failed, using safe defaults.' };
try {
  let raw = '';
  const parts = aiResp?.candidates?.[0]?.content?.parts || [];
  for (const p of parts) { if (p && p.text) raw += p.text; }
  if (raw) {
    let t = raw.replace(/```json/gi, '').replace(/```/g, '').trim();
    const s = t.indexOf('{'), e = t.lastIndexOf('}');
    if (s >= 0 && e > s) t = t.substring(s, e + 1);
    analysis = JSON.parse(t);
  }
} catch (e) {
  analysis.decisions = d.pendingCarts.map(c => ({
    cart_id: c.cartId, approach: 'SOFT_DISCOUNT_10', channel: 'email', tone: 'warm',
    discount_percent: 10, promo_code: 'GLOW10', reasoning: 'Fallback safe nudge (AI parse failed)',
    email_subject: 'You left something behind', email_body: 'Hi ' + c.customerName + ', your cart is waiting.',
    whatsapp_message: '👋 Hi ' + c.customerName + ',\n\nYour cart at GlowVeda is waiting 🛍️\nReady to complete your order?\n\n🎁 10% off with code GLOW10\n\n👉 [CART_LINK]\n\n— Team GlowVeda 💖',
    products_breakdown: [c.products || 'your items'],
    headline_text: 'Hi ' + c.customerName + ', your cart is waiting',
    urgency_line: 'Your items are popular and selling fast!',
    touch_number: 1, expected_recovery_probability: '15%'
  }));
}

// Promo code map (used if AI doesn't return one)
const codeMap = {
  NUDGE_NO_DISCOUNT: '',
  SOFT_DISCOUNT_10: 'GLOW10',
  URGENT_DISCOUNT_15: 'BACK15',
  LOYALTY_DISCOUNT_20: 'VIP20',
  WIN_BACK_25: 'COMEBACK25'
};

const decMap = {};
(analysis.decisions || []).forEach(dec => {
  if (!dec || !dec.cart_id || !dec.approach || !dec.channel) return;
  decMap[dec.cart_id] = dec;
});

const toProcess = [];
d.pendingCarts.forEach(c => {
  if (!c.cartId) return;
  const dec = decMap[c.cartId];
  if (!dec || dec.approach === 'SKIP' || dec.channel === 'skip') return;
  if (!c.customerEmail && !c.customerPhone) return;

  // Promo code — use AI's choice, fallback to map
  const promoCode = dec.promo_code || codeMap[dec.approach] || '';
  const discount = dec.discount_percent || 0;
  const savings = Math.round((c.cartValue * discount) / 100);
  const finalPrice = c.cartValue - savings;

  // Cart link with auto-apply discount code
  const cartLink = 'https://yourbrand.com/recover-cart?cid=' + encodeURIComponent(c.cartId) +
                   '&token=' + Date.now().toString(36) +
                   (promoCode ? '&code=' + promoCode : '');

  const emailBody = String(dec.email_body || '').replace(/\[CART_LINK\]/g, cartLink);
  const whatsappMsg = String(dec.whatsapp_message || '').replace(/\[CART_LINK\]/g, cartLink);

  if (!emailBody && !whatsappMsg) return;

  toProcess.push({
    cart: c,
    decision: dec,
    cartLink, emailBody, whatsappMsg,
    promoCode, savings, finalPrice,
    productsBreakdown: dec.products_breakdown || [c.products || 'your items'],
    headlineText: dec.headline_text || ('Hi ' + c.customerName + ', your cart is waiting'),
    urgencyLine: dec.urgency_line || 'These items are popular and selling fast!',
    sendEmail: (dec.channel === 'email' || dec.channel === 'both') && !!c.customerEmail && !!emailBody,
    sendWhatsapp: (dec.channel === 'whatsapp' || dec.channel === 'both') && !!c.customerPhone && !!whatsappMsg
  });
});

const counts = { NUDGE_NO_DISCOUNT:0, SOFT_DISCOUNT_10:0, URGENT_DISCOUNT_15:0, LOYALTY_DISCOUNT_20:0, WIN_BACK_25:0, SKIP:0 };
(analysis.decisions || []).forEach(dec => { if (counts[dec.approach] !== undefined) counts[dec.approach]++; });

// Total cart value at stake (for owner alert)
const totalValueAtStake = toProcess.reduce((s, p) => s + p.cart.cartValue, 0);
const totalPotentialSavings = toProcess.reduce((s, p) => s + p.savings, 0);

return [{ json: { ...d, analysis, toProcess, counts, processCount: toProcess.length, totalValueAtStake, totalPotentialSavings, batchSummary: analysis.batch_summary || '', runTime: new Date().toISOString() } }];

// Premium itemized email template — light theme, items table, gradient promo banner, big CTA
const d = $input.first().json;

const c = {
  brand: '#0f172a',     // deep navy header
  brandLight: '#1e293b',
  accent: '#f97316',    // orange CTA gradient start
  accentDeep: '#dc2626', // red CTA gradient end
  cta1: '#7c3aed',      // purple CTA
  cta2: '#4f46e5',      // indigo CTA
  cardBg: '#ffffff',
  cardBorder: '#e2e8f0',
  text: '#0f172a',
  textLight: '#64748b',
  textMuted: '#94a3b8',
  urgentRed: '#dc2626',
  savingsGreen: '#16a34a',
  rowBg: '#f8fafc',
  pageBg: '#f1f5f9'
};

const touchLabel = d.touchNumber === 1 ? 'Friendly Reminder' :
                   d.touchNumber === 2 ? 'Quick Follow-up' :
                   d.touchNumber >= 3 ? 'Last Chance' : 'Cart Update';

const headline = d.headlineText || ('Hi ' + d.customerName + ', your cart is waiting');
const urgency = d.urgencyLine || 'These items are popular and selling fast!';

// Render product items
const itemRows = (d.productsBreakdown || [d.products || 'Your items']).map(item =>
  '<tr>' +
    '<td style="padding:14px 8px;border-bottom:1px solid ' + c.cardBorder + ';">' +
      '<table style="border-collapse:collapse;"><tr>' +
        '<td style="width:40px;padding-right:12px;"><div style="width:36px;height:36px;background:' + c.rowBg + ';border-radius:6px;display:inline-block;text-align:center;line-height:36px;font-size:18px;">📦</div></td>' +
        '<td style="color:' + c.text + ';font-size:14px;font-weight:600;">' + item + '</td>' +
      '</tr></table>' +
    '</td>' +
    '<td style="padding:14px 8px;text-align:center;color:' + c.textLight + ';font-size:13px;border-bottom:1px solid ' + c.cardBorder + ';">x1</td>' +
  '</tr>'
).join('');

// Discount banner (only if discount > 0)
let promoBanner = '';
if (d.discount > 0 && d.promoCode) {
  promoBanner =
    '<div style="background:linear-gradient(135deg,' + c.accent + ' 0%,' + c.accentDeep + ' 100%);border-radius:12px;padding:22px;text-align:center;margin:20px 0;">' +
      '<p style="color:#fff;font-size:11px;font-weight:700;margin:0 0 6px;letter-spacing:2px;">🎁 EXCLUSIVE OFFER FOR YOU</p>' +
      '<p style="color:#fff;font-size:32px;font-weight:900;letter-spacing:3px;margin:4px 0;font-family:Arial Black,sans-serif;">' + d.promoCode + '</p>' +
      '<p style="color:#fff;font-size:14px;margin:6px 0 0;">Use this code for <b>' + d.discount + '% OFF</b> — Save ₹' + d.savings + '!</p>' +
    '</div>';
}

// Pricing breakdown table footer
let pricingRows = '<tr><td colspan="2" style="padding:14px 8px;border-bottom:1px solid ' + c.cardBorder + ';"><table style="width:100%;border-collapse:collapse;"><tr><td style="color:' + c.text + ';font-size:14px;font-weight:700;">Cart Total</td><td style="text-align:right;color:' + c.text + ';font-size:16px;font-weight:800;">₹' + d.cartValue.toLocaleString('en-IN') + '</td></tr></table></td></tr>';
if (d.discount > 0) {
  pricingRows += '<tr><td colspan="2" style="padding:10px 8px;"><table style="width:100%;border-collapse:collapse;"><tr>' +
    '<td style="color:' + c.savingsGreen + ';font-size:13px;font-weight:600;">After ' + (d.promoCode || '') + ' (' + d.discount + '% off)</td>' +
    '<td style="text-align:right;color:' + c.savingsGreen + ';font-size:16px;font-weight:800;">₹' + d.finalPrice.toLocaleString('en-IN') + '</td>' +
    '</tr></table></td></tr>';
}

const tierBadge = d.customerTier === 'premium'
  ? '<span style="background:' + c.accent + ';color:#fff;padding:4px 12px;border-radius:14px;font-size:10px;font-weight:800;letter-spacing:1px;display:inline-block;margin-top:8px;">⭐ PREMIUM MEMBER</span>'
  : '';

const body = (d.emailBody || '').replace(/\n/g, '<br>');

const html =
'<div style="background:' + c.pageBg + ';padding:32px 16px;font-family:Segoe UI,Arial,sans-serif;">' +
  '<div style="max-width:640px;margin:0 auto;background:' + c.cardBg + ';border-radius:16px;overflow:hidden;box-shadow:0 4px 20px rgba(15,23,42,0.08);">' +

    // Navy header band
    '<div style="background:' + c.brand + ';padding:28px 24px;text-align:center;">' +
      '<h1 style="color:#fff;font-size:24px;font-weight:800;margin:0;letter-spacing:1px;">GlowVeda</h1>' +
      '<p style="color:#94a3b8;font-size:12px;margin:4px 0 0;letter-spacing:3px;text-transform:uppercase;">' + touchLabel + '</p>' +
    '</div>' +

    // Body
    '<div style="padding:32px 28px;">' +

      // Hero title
      '<h2 style="color:' + c.text + ';font-size:24px;font-weight:800;margin:0 0 8px;line-height:1.3;">' + headline + ' 🛍️</h2>' +
      tierBadge +

      // Personal message from AI
      '<p style="color:' + c.textLight + ';font-size:15px;line-height:1.7;margin:18px 0 0;">' + body + '</p>' +

      // Urgency line
      '<p style="color:' + c.urgentRed + ';font-size:14px;font-weight:600;line-height:1.6;margin:18px 0 0;">⏰ ' + urgency + '</p>' +

      // Cart breakdown card
      '<div style="background:' + c.rowBg + ';border:1px solid ' + c.cardBorder + ';border-radius:12px;padding:18px;margin:24px 0 0;">' +
        '<p style="color:' + c.text + ';font-size:13px;font-weight:700;margin:0 0 12px;letter-spacing:1px;">🛒 YOUR CART</p>' +
        '<table style="width:100%;border-collapse:collapse;">' +
          '<thead><tr>' +
            '<th style="text-align:left;padding:8px 8px;color:' + c.textMuted + ';font-size:10px;font-weight:700;letter-spacing:1px;border-bottom:1px solid ' + c.cardBorder + ';">ITEM</th>' +
            '<th style="text-align:center;padding:8px 8px;color:' + c.textMuted + ';font-size:10px;font-weight:700;letter-spacing:1px;border-bottom:1px solid ' + c.cardBorder + ';">QTY</th>' +
          '</tr></thead>' +
          '<tbody>' + itemRows + pricingRows + '</tbody>' +
        '</table>' +
      '</div>' +

      // Promo banner (only when discount)
      promoBanner +

      // Big CTA button
      '<div style="text-align:center;margin:24px 0 8px;">' +
        '<a href="' + d.cartLink + '" style="display:inline-block;background:linear-gradient(135deg,' + c.cta1 + ' 0%,' + c.cta2 + ' 100%);color:#fff;padding:16px 44px;border-radius:50px;text-decoration:none;font-size:15px;font-weight:700;letter-spacing:0.5px;box-shadow:0 4px 14px rgba(124,58,237,0.35);">Complete My Order Now →</a>' +
      '</div>' +

      // Helper text
      '<p style="color:' + c.textMuted + ';font-size:11px;text-align:center;margin:14px 0 0;">Or <a href="' + d.cartLink + '" style="color:' + c.cta1 + ';text-decoration:underline;">click here</a> to return to your cart</p>' +

    '</div>' +

    // Footer
    '<div style="background:' + c.rowBg + ';padding:18px 28px;text-align:center;border-top:1px solid ' + c.cardBorder + ';">' +
      '<p style="color:' + c.textMuted + ';font-size:10px;margin:6px 0 0;">© GlowVeda — Premium Indian Skincare</p>' +
    '</div>' +

  '</div>' +
'</div>';

return [{ json: { ...d, recoveryHtml: html } }];

const data = $input.first().json;
const carts = data.cartSends || [];

const enriched = carts.map(cart => {
  const ltv = cart.customerHistory?.lifetimeValue || 0;
  const orders = cart.customerHistory?.lifetimeOrders || 0;
  const tier = cart.customerHistory?.tier || 'standard';
  const pastRecoveries = cart.customerHistory?.pastRecoveries || 0;
  const pastAbandons = cart.customerHistory?.pastAbandons || 0;

  let vipScore = 0;
  if (ltv > 10000) vipScore += 3;
  else if (ltv > 5000) vipScore += 2;
  else if (ltv > 2000) vipScore += 1;
  if (orders > 5) vipScore += 2;
  else if (orders > 2) vipScore += 1;
  if (tier === 'premium') vipScore += 2;
  if (pastRecoveries > 1) vipScore += 1;

  const isVip = vipScore >= 4;
  const recoveryRisk = pastAbandons > 2 && pastRecoveries === 0 ? 'high' : 'normal';

  return {
    ...cart,
    vipScore,
    isVip,
    recoveryRisk,
    recommendedApproach: isVip ? 'PREMIUM' : (recoveryRisk === 'high' ? 'WIN_BACK' : cart.approach)
  };
});

return [{ json: { ...data, cartSends: enriched } }];

const data = $input.first().json;
const carts = data.cartSends || [];

const vipCarts = carts.filter(c => c.isVip);
const highRiskCarts = carts.filter(c => c.recoveryRisk === 'high' && !c.isVip);
const standardCarts = carts.filter(c => !c.isVip && c.recoveryRisk !== 'high');

return [{ json: {
  ...data,
  cartSends: carts,
  vipCount: vipCarts.length,
  highRiskCount: highRiskCarts.length,
  standardCount: standardCarts.length,
  vipCartIds: vipCarts.map(c => c.cartId)
}}];

const data = $input.first().json;
const carts = data.cartSends || [];

const enriched = carts.map(cart => {
  const cartValue = cart.cartValue || 0;
  const tier = cart.customerHistory?.tier || 'standard';
  const pastAbandons = cart.customerHistory?.pastAbandons || 0;
  const pastRecoveries = cart.customerHistory?.pastRecoveries || 0;
  const lastDiscount = cart.customerHistory?.lastDiscountUsed || 0;
  const isVip = cart.isVip || false;
  const approach = cart.recommendedApproach || cart.approach || '';

  let discountPct = 0;
  let discountReason = '';

  if (isVip) {
    discountPct = 0;
    discountReason = 'VIP customer — no discount needed, use brand value';
  } else if (approach === 'WIN_BACK') {
    discountPct = pastAbandons > 3 ? 25 : 20;
    discountReason = 'Win-back offer for repeat abandoner';
  } else if (approach === 'DISCOUNT') {
    if (cartValue > 2000) discountPct = 10;
    else if (cartValue > 1000) discountPct = 15;
    else discountPct = 20;
    discountReason = 'Standard discount scaled to cart value';
  } else if (approach === 'URGENCY' || approach === 'FOMO') {
    discountPct = 5;
    discountReason = 'Small nudge to reinforce urgency';
  } else {
    discountPct = 0;
    discountReason = 'No discount — approach does not require it';
  }

  if (discountPct > 0 && lastDiscount >= discountPct) {
    discountPct = Math.min(discountPct + 5, 30);
    discountReason += ' (increased — last discount was equal or higher)';
  }

  const discountAmount = Math.round(cartValue * discountPct / 100);
  const finalPrice = Math.round(cartValue - discountAmount);

  return {
    ...cart,
    discountPct,
    discountAmount,
    finalPrice,
    discountReason
  };
});

return [{ json: { ...data, cartSends: enriched } }];

const data = $input.first().json;
const carts = data.cartSends || [];
const recoveryLog = data.recoveryLog || [];

const totalCarts = carts.length;
const vipCarts = data.vipCount || 0;
const highRiskCarts = data.highRiskCount || 0;
const totalCartValue = carts.reduce((sum, c) => sum + (c.cartValue || 0), 0);

const approachBreakdown = {};
carts.forEach(c => {
  const approach = c.recommendedApproach || c.approach || 'UNKNOWN';
  approachBreakdown[approach] = (approachBreakdown[approach] || 0) + 1;
});

const discountedCarts = carts.filter(c => c.discountPct > 0);
const totalDiscountValue = discountedCarts.reduce((sum, c) => sum + (c.discountAmount || 0), 0);
const avgDiscount = discountedCarts.length > 0 ? Math.round(discountedCarts.reduce((sum, c) => sum + c.discountPct, 0) / discountedCarts.length) : 0;

const historicalRecoveries = recoveryLog.filter(r => r.Outcome === 'RECOVERED');
const historicalRecoveryRate = recoveryLog.length > 0 ? Math.round(historicalRecoveries.length / recoveryLog.length * 100) : 0;
const totalRecoveredValue = historicalRecoveries.reduce((sum, r) => sum + (parseFloat(r['Recovered Value']) || 0), 0);

const performanceSummary = {
  runTime: new Date().toISOString(),
  cartsProcessed: totalCarts,
  vipCarts,
  highRiskCarts,
  totalCartValueAtRisk: totalCartValue,
  approachBreakdown,
  discountedCarts: discountedCarts.length,
  totalDiscountOffered: totalDiscountValue,
  avgDiscountPct: avgDiscount,
  historicalRecoveryRate: historicalRecoveryRate + '%',
  totalRevenueRecovered: totalRecoveredValue,
  estimatedRecoveryThisRun: Math.round(totalCartValue * (historicalRecoveryRate / 100))
};

return [{ json: { ...data, performanceSummary } }];

